from appium.webdriver.common.appiumby import AppiumBy
from selenium.webdriver.support.ui import WebDriverWait
from selenium.webdriver.support import expected_conditions as EC

# Try common cancel/dismiss button patterns
try:
    cancel_button = WebDriverWait(driver, 10).until(
        EC.element_to_be_clickable((AppiumBy.ACCESSIBILITY_ID, "cancel_trial"))
    )
    cancel_button.click()
except:
    try:
        cancel_button = WebDriverWait(driver, 10).until(
            EC.element_to_be_clickable((AppiumBy.ACCESSIBILITY_ID, "no_thanks"))
        )
        cancel_button.click()
    except:
        cancel_button = WebDriverWait(driver, 10).until(
            EC.element_to_be_clickable((AppiumBy.ACCESSIBILITY_ID, "dismiss"))
        )
        cancel_button.click()
